import httpx
from fastapi import FastAPI
import os
from dotenv import load_dotenv

load_dotenv()

app = FastAPI(title='Todo Email API')

FROM_EMAIL = os.environ.get('FROM_EMAIL', '')
RESEND_API_KEY = os.environ.get('RESEND_API_KEY', '')

def send_email_resend(to: str, subject: str, body: str):
    response = httpx.post(
        'https://api.resend.com/emails',
        headers={
            'Authorization': f'Bearer {RESEND_API_KEY}',
            'Content-Type': 'application/json'
        },
        json={
            'from': FROM_EMAIL,
            'to': [to],
            'subject': subject,
            'text': body
        }
    )
    response.raise_for_status()
    return response.json()

@app.post('/todos/{todo_id}/remind')
def send_reminder(todo_id: int, email: str):
    send_email_resend(email, 'Todo reminder', f'Reminder for todo #{todo_id}')
    return {'sent': True}

