from fastapi import FastAPI, BackgroundTasks
import httpx
import os
from dotenv import load_dotenv

load_dotenv()

app = FastAPI(title='Todo Email API')

FROM_EMAIL = os.environ.get('FROM_EMAIL', '')
RESEND_API_KEY = os.environ.get('RESEND_API_KEY', '')

def send_email_resend(to: str, subject: str, text: str, html: str = None):
    body = {'from': FROM_EMAIL, 'to': [to], 'subject': subject, 'text': text}
    if html:
        body['html'] = html
    response = httpx.post(
        'https://api.resend.com/emails',
        headers={'Authorization': f'Bearer {RESEND_API_KEY}'},
        json=body
    )
    response.raise_for_status()

def reminder_html(todo_id: int, todo_text: str) -> str:
    return f'<html><body><h2>Reminder</h2><p>{todo_text}</p></body></html>'

# Update this route to accept BackgroundTasks and queue the email
@app.post('/todos/{todo_id}/remind')
def send_reminder(todo_id: int, email: str, todo_text: str):
    send_email_resend(email, 'Todo reminder', f'Reminder: {todo_text}', html=reminder_html(todo_id, todo_text))
    return {'sent': True}
